import{B as e,Q as t,s as n,z as r}from"./chunks/framework.GF8LbaeE.js";var i=JSON.parse(`{"title":"General Manager","description":"","frontmatter":{},"headers":[],"relativePath":"guide/general-manager.md","filePath":"guide/general-manager.md"}`),a={name:`guide/general-manager.md`};function o(n,i,a,o,s,c){return t(),r(`div`,null,[...i[0]||=[e(`<h1 id="general-manager" tabindex="-1">General Manager <a class="header-anchor" href="#general-manager" aria-label="Permalink to &quot;General Manager&quot;">​</a></h1><p>Welcome to the General Manager guide. This documentation is automatically generated from the latest game features.</p><h2 id="gm-dashboard" tabindex="-1">GM Dashboard <a class="header-anchor" href="#gm-dashboard" aria-label="Permalink to &quot;GM Dashboard&quot;">​</a></h2><p>The GM Dashboard provides a high-level overview of brand performance, including total budget, roster health, and locker room morale. GMs can track financial trends and identify exhausted or unhappy wrestlers at a glance.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-gm-dashboard.png" alt="GM Dashboard"></p><hr><h2 id="contract-management" tabindex="-1">Contract Management <a class="header-anchor" href="#contract-management" aria-label="Permalink to &quot;Contract Management&quot;">​</a></h2><p>View and manage active wrestler contracts. Salaries are dynamically tied to fan count, forcing GMs to balance the cost of superstars with the development of new talent.</p><p><img src="/all-time-wrestling-rpg/screenshots/admin-contract-management.png" alt="Contract Management"></p><hr><h2 id="video-walkthroughs" tabindex="-1">Video Walkthroughs <a class="header-anchor" href="#video-walkthroughs" aria-label="Permalink to &quot;Video Walkthroughs&quot;">​</a></h2><h3 id="contract-management-walkthrough" tabindex="-1">Contract Management Walkthrough <a class="header-anchor" href="#contract-management-walkthrough" aria-label="Permalink to &quot;Contract Management Walkthrough&quot;">​</a></h3><p>Salary scales with a wrestler&#39;s fan base — Main Eventers command higher pay than Rookies. Monitor total payroll here to avoid overspending on roster depth at the expense of developing the next headliner.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/contract-management-walkthrough.mp4" type="video/mp4"></video><hr><h3 id="gm-dashboard-walkthrough" tabindex="-1">GM Dashboard Walkthrough <a class="header-anchor" href="#gm-dashboard-walkthrough" aria-label="Permalink to &quot;GM Dashboard Walkthrough&quot;">​</a></h3><p>Exhausted or unhappy wrestlers underperform in matches and lose fans over time. Review this dashboard before booking shows to identify who needs rest and who is primed for a featured main-event spot.</p><video controls width="100%" style="border-radius:8px;margin-bottom:1rem;"><source src="https://javydreamercsw.github.io/all-time-wrestling-rpg/videos/gm-dashboard-walkthrough.mp4" type="video/mp4"></video><hr>`,19)]])}var s=n(a,[[`render`,o]]);export{i as __pageData,s as default};